import { useState } from "react";
import { useNavigate } from "react-router-dom";
import CustomerForm, { emptyCustomerForm } from "../components/CustomerForm";
import API, { getApiError } from "../services/api";

export default function AddCustomer() {
  const navigate = useNavigate();
  const [form, setForm] = useState(emptyCustomerForm);
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  const updateField = (key, value) => {
    setForm((current) => ({ ...current, [key]: value }));
  };

  const handlePhotoChange = (photo) => {
    updateField("photo", photo);
    setError("");
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setError("");

    if (!form.fullName || !form.phone || !form.age || !form.amountPaid) {
      setError("Please fill in name, phone, age, and amount paid before saving.");
      return;
    }

    setSaving(true);

    try {
      await API.post("/customers", {
        ...form,
        age: Number(form.age),
        amountPaid: Number(form.amountPaid)
      });

      navigate("/customers", {
        state: { message: `${form.fullName} was added successfully.` }
      });
    } catch (requestError) {
      setError(getApiError(requestError, "Unable to add this customer."));
    } finally {
      setSaving(false);
    }
  };

  return (
    <CustomerForm
      eyebrow="New membership"
      title="Add a customer"
      description="Add a new member and assign a plan."
      form={form}
      error={error}
      saving={saving}
      submitLabel="Create customer"
      savingLabel="Saving..."
      onSubmit={handleSubmit}
      onChange={updateField}
      onPhotoChange={handlePhotoChange}
      secondaryAction={() => setForm(emptyCustomerForm)}
      secondaryLabel="Reset form"
      previewStartDate={new Date().toISOString().split("T")[0]}
    />
  );
}
